        [Fact]
        public void DecodeBasic()
        {
            var decoded = new FlateDecodeFilter(null).Decode(_encoded);

            var output = Encoding.ASCII.GetString(decoded);

            output.Should().Be(_decoded);
        }

        [Fact]
        public void EncodeBasic()
        {
            var input = Encoding.ASCII.GetBytes(_decoded);

            var encoded = new FlateDecodeFilter(null).Encode(input);

            encoded.Should().BeEquivalentTo(_encoded);
        }

        [Fact]
        public void DecodeBasic2()
        {
            var encoded = new byte[] { 120, 1, 50, 52, 50, 54, 49, 5, 0, 0, 0, 255, 255, 2, 248, 1, 0 };

            var decoded = new FlateDecodeFilter(null).Decode(encoded);

            var output = Encoding.ASCII.GetString(decoded);

            var expectedOutput = "12345";

            output.Should().Be(expectedOutput);
        }

        [Fact]
        public void EncodeBasic2()
        {
            var inputString = "12345";
            var input = Encoding.ASCII.GetBytes(inputString);

            var encoded = new FlateDecodeFilter(null).Encode(input);

            var expectedOutput = new byte[] { 120, 1, 50, 52, 50, 54, 49, 5, 0, 0, 0, 255, 255, 2, 248, 1, 0 };

            encoded.Should().BeEquivalentTo(expectedOutput);
        }
